import React, { useState, useRef, useEffect, useCallback } from 'react';

const SIZE = 15;
const CELL = 18;

const randomCell = () => ({ x: Math.floor(Math.random() * SIZE), y: Math.floor(Math.random() * SIZE) });

export default function SnakeGame() {
  const [snake, setSnake] = useState([{ x: 7, y: 7 }]);
  const [food, setFood] = useState({ x: 3, y: 3 });
  const [over, setOver] = useState(false);
  const [score, setScore] = useState(0);
  const dir = useRef({ x: 1, y: 0 });

  const tick = useCallback(() => {
    setSnake((s) => {
      const head = { x: s[0].x + dir.current.x, y: s[0].y + dir.current.y };
      if (head.x < 0 || head.y < 0 || head.x >= SIZE || head.y >= SIZE || s.some((c) => c.x === head.x && c.y === head.y)) {
        setOver(true);
        return s;
      }
      const grew = head.x === food.x && head.y === food.y;
      const next = [head, ...s];
      if (grew) {
        setScore((sc) => sc + 1);
        let f = randomCell();
        while (next.some((c) => c.x === f.x && c.y === f.y)) f = randomCell();
        setFood(f);
      } else {
        next.pop();
      }
      return next;
    });
  }, [food]);

  useEffect(() => {
    if (over) return;
    const id = setInterval(tick, 150);
    return () => clearInterval(id);
  }, [tick, over]);

  const onKey = (e) => {
    const map = {
      ArrowUp: { x: 0, y: -1 },
      ArrowDown: { x: 0, y: 1 },
      ArrowLeft: { x: -1, y: 0 },
      ArrowRight: { x: 1, y: 0 },
    };
    const d = map[e.key];
    if (!d) return;
    e.preventDefault();
    if (d.x !== -dir.current.x || d.y !== -dir.current.y) dir.current = d;
  };

  const restart = () => {
    setSnake([{ x: 7, y: 7 }]);
    setFood({ x: 3, y: 3 });
    dir.current = { x: 1, y: 0 };
    setScore(0);
    setOver(false);
  };

  return (
    <div>
      <p style={{ fontWeight: 600 }}>Score: {score} {over && '— Game over'}</p>
      <div
        tabIndex={0}
        onKeyDown={onKey}
        style={{ position: 'relative', width: SIZE * CELL, height: SIZE * CELL, background: '#0f172a', outline: 'none', borderRadius: 6 }}
      >
        {snake.map((c, i) => (
          <div key={i} style={{ position: 'absolute', left: c.x * CELL, top: c.y * CELL, width: CELL - 1, height: CELL - 1, background: i === 0 ? '#4ade80' : '#22c55e', borderRadius: 3 }} />
        ))}
        <div style={{ position: 'absolute', left: food.x * CELL, top: food.y * CELL, width: CELL - 1, height: CELL - 1, background: '#ef4444', borderRadius: '50%' }} />
      </div>
      {over && <button onClick={restart} style={{ marginTop: 12, padding: '8px 16px', cursor: 'pointer' }}>Restart</button>}
    </div>
  );
}

