import { Component, OnInit, OnDestroy, HostListener } from '@angular/core';
import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';

interface Cell { x: number; y: number; }

const SIZE = 15;
const CELL = 18;

@Component({
  selector: 'app-snake-game',
  template: `
    <div>
      <p style="font-weight: 600;">Score: {{ score }} <span *ngIf="over">— Game over</span></p>
      <div style="position: relative; background: #0f172a; border-radius: 6px;" [style.width.px]="size * cell" [style.height.px]="size * cell">
        <div
          *ngFor="let c of snake; let i = index"
          style="position: absolute; border-radius: 3px;"
          [style.left.px]="c.x * cell"
          [style.top.px]="c.y * cell"
          [style.width.px]="cell - 1"
          [style.height.px]="cell - 1"
          [style.background]="i === 0 ? '#4ade80' : '#22c55e'"
        ></div>
        <div
          style="position: absolute; background: #ef4444; border-radius: 50%;"
          [style.left.px]="food.x * cell"
          [style.top.px]="food.y * cell"
          [style.width.px]="cell - 1"
          [style.height.px]="cell - 1"
        ></div>
      </div>
      <button *ngIf="over" (click)="restart()" style="margin-top: 12px; padding: 8px 16px; cursor: pointer;">Restart</button>
    </div>
  `,
})
export class SnakeGameComponent implements OnInit, OnDestroy {
  readonly size = SIZE;
  readonly cell = CELL;
  snake: Cell[] = [{ x: 7, y: 7 }];
  food: Cell = { x: 3, y: 3 };
  dir: Cell = { x: 1, y: 0 };
  over = false;
  score = 0;
  private id: any = null;

  randomCell(): Cell {
    return { x: Math.floor(Math.random() * SIZE), y: Math.floor(Math.random() * SIZE) };
  }

  randomFree(occupied: Cell[]): Cell {
    let f = this.randomCell();
    while (occupied.some((c) => c.x === f.x && c.y === f.y)) {
      f = this.randomCell();
    }
    return f;
  }

  tick(): void {
    const head = { x: this.snake[0].x + this.dir.x, y: this.snake[0].y + this.dir.y };
    if (
      head.x < 0 || head.y < 0 || head.x >= SIZE || head.y >= SIZE ||
      this.snake.some((c) => c.x === head.x && c.y === head.y)
    ) {
      this.over = true;
      clearInterval(this.id);
      return;
    }
    const grew = head.x === this.food.x && head.y === this.food.y;
    const next = [head, ...this.snake];
    if (grew) {
      this.score++;
      this.food = this.randomFree(next);
    } else {
      next.pop();
    }
    this.snake = next;
  }

  @HostListener('window:keydown', ['$event'])
  onKey(e: KeyboardEvent): void {
    const map: Record<string, Cell> = {
      ArrowUp: { x: 0, y: -1 },
      ArrowDown: { x: 0, y: 1 },
      ArrowLeft: { x: -1, y: 0 },
      ArrowRight: { x: 1, y: 0 },
    };
    const d = map[e.key];
    if (!d) {
      return;
    }
    e.preventDefault();
    if (d.x !== -this.dir.x || d.y !== -this.dir.y) {
      this.dir = d;
    }
  }

  restart(): void {
    this.snake = [{ x: 7, y: 7 }];
    this.food = { x: 3, y: 3 };
    this.dir = { x: 1, y: 0 };
    this.score = 0;
    this.over = false;
    clearInterval(this.id);
    this.id = setInterval(() => this.tick(), 150);
  }

  ngOnInit(): void {
    this.id = setInterval(() => this.tick(), 150);
  }

  ngOnDestroy(): void {
    clearInterval(this.id);
  }
}

@Component({
  selector: 'app-root',
  template: `
    <div style="font-family: sans-serif; padding: 20px;">
      <h1>Snake Demo</h1>
      <p style="color: #666;">Use arrow keys.</p>
      <app-snake-game></app-snake-game>
    </div>
  `,
})
export class AppComponent {}

@NgModule({
  declarations: [AppComponent, SnakeGameComponent],
  imports: [BrowserModule],
  bootstrap: [AppComponent],
})
export class AppModule {}
